101: func (s *Store) CountFlags(ctx context.Context, p storage.NamespaceRequest) (count uint64, err error) {
102: 	return count, s.viewer.View(ctx, p.Reference, func(ss storage.ReadOnlyStore) error {
103: 		count, err = ss.CountFlags(ctx, p)
104: 		return err
105: 	})
106: }
