108: func (s *Store) GetRule(ctx context.Context, p storage.NamespaceRequest, id string) (rule *flipt.Rule, err error) {
109: 	return rule, s.viewer.View(ctx, p.Reference, func(ss storage.ReadOnlyStore) error {
110: 		rule, err = ss.GetRule(ctx, p, id)
111: 		return err
