92: func SnapshotFromPaths(logger *zap.Logger, ffs fs.FS, paths []string, opts ...containers.Option[SnapshotOption]) (*Snapshot, error) {
93: 	logger.Debug("opening state files", zap.Strings("paths", paths))
94: 
95: 	var files []fs.File
96: 	for _, file := range paths {
97: 		fi, err := ffs.Open(file)
