110: func SnapshotFromFiles(logger *zap.Logger, files []fs.File, opts ...containers.Option[SnapshotOption]) (*Snapshot, error) {
111: 	now := flipt.Now()
112: 	s := Snapshot{
113: 		ns: map[string]*namespace{
