63: func (s *Store) GetEvaluationRules(ctx context.Context, flag storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
64: 	cacheKey := fmt.Sprintf(evaluationRulesCacheKeyFmt, flag.Namespace(), flag.Key)
65: 
66: 	var rules []*storage.EvaluationRule
67: 
68: 	cacheHit := s.get(ctx, cacheKey, &rules)
69: 	if cacheHit {
70: 		return rules, nil
71: 	}
72: 
73: 	rules, err := s.Store.GetEvaluationRules(ctx, flag)
74: 	if err != nil {
75: 		return nil, err
76: 	}
