			&variant.FlagKey,
			&variant.Name,
			&variant.Description,
			&variant.Attachment,
			&vCreatedAt,
			&vUpdatedAt); err != nil {
			return err
		}

		if flag, ok := flagsByKey[variant.FlagKey.String]; ok {
			flag.Variants = append(flag.Variants, &flipt.Variant{
